import anime from"../anime.min.js";function sleep(ms){return new Promise(resolve=>setTimeout(resolve,ms))}function clamp(value,min,max){return Math.min(Math.max(value,min),max)}function downloadFile(filename){var e=document.createElement("a");e.href=filename,e.download=filename.slice(filename.lastIndexOf("/")+1),document.body.appendChild(e),e.click(),e.remove()}function downloadString(text,filename){var e=new Blob([text],{type:"text/plain"}),e=URL.createObjectURL(e),t=document.createElement("a");t.href=e,t.download=filename,t.click(),URL.revokeObjectURL(e)}async function asyncFetch(url){return await(await fetch(url)).text()}async function animate(update,duration,easing="easeOutQuad"){if(0===duration)update(1);else{const e={t:0};await anime({targets:e,t:1,duration:duration,easing:easing,update:()=>update(e.t),complete:()=>update(1)}).finished}}function fuzzySearch(query,names,threshold=.3){var e=[],t=query.toLowerCase();for(const n of names){var a=calculateSimilarity(t,n.toLowerCase());threshold<=a&&e.push({name:n,score:a})}return e.sort((a,b)=>b.score-a.score).map(result=>result.name)}function calculateSimilarity(query,target){if(query===target)return 1;if(0===query.length||0===target.length)return 0;if(target.startsWith(query))return.95+query.length/target.length*.05;var e;for(const n of target.split(" "))if(n.startsWith(query))return.85+query.length/n.length*.1;if(target.includes(query))return.6+query.length/target.length*.2;let t=0,a=0;for(let r=0;r<target.length&&a<query.length;r++)target[r]===query[a]&&(e=1-r/target.length*.8,t+=e,a++);return Math.min(t/query.length,.5)}export{sleep,clamp,downloadFile,downloadString,asyncFetch,animate,fuzzySearch};